// AIStudioManagementServiceServer is the server API for AIStudioManagementService service.
// All implementations must embed UnimplementedAIStudioManagementServiceServer
// for forward compatibility.
//
// AIStudioManagementService provides AI Studio plugins with access to core management operations
// Plugins must be authorized by admin and have appropriate scopes to access these services
type AIStudioManagementServiceServer interface {
	// Plugin Management Operations
	ListPlugins(context.Context, *ListPluginsRequest) (*ListPluginsResponse, error)
	GetPlugin(context.Context, *GetPluginRequest) (*GetPluginResponse, error)
	UpdatePluginConfig(context.Context, *UpdatePluginConfigRequest) (*UpdatePluginConfigResponse, error)
	// LLM Management Operations
	ListLLMs(context.Context, *ListLLMsRequest) (*ListLLMsResponse, error)
	GetLLM(context.Context, *GetLLMRequest) (*GetLLMResponse, error)
	GetLLMPlugins(context.Context, *GetLLMPluginsRequest) (*GetLLMPluginsResponse, error)
	CreateLLM(context.Context, *CreateLLMRequest) (*CreateLLMResponse, error)
	UpdateLLM(context.Context, *UpdateLLMRequest) (*UpdateLLMResponse, error)
	DeleteLLM(context.Context, *DeleteLLMRequest) (*DeleteLLMResponse, error)
	// Analytics Operations (with caching)
	GetAnalyticsSummary(context.Context, *GetAnalyticsSummaryRequest) (*GetAnalyticsSummaryResponse, error)
	GetUsageStatistics(context.Context, *GetUsageStatisticsRequest) (*GetUsageStatisticsResponse, error)
	GetCostAnalysis(context.Context, *GetCostAnalysisRequest) (*GetCostAnalysisResponse, error)
	// Detailed Analytics Operations (Phase 2.1)
	GetChatRecordsPerDay(context.Context, *GetChatRecordsPerDayRequest) (*GetChatRecordsPerDayResponse, error)
	GetModelUsage(context.Context, *GetModelUsageRequest) (*GetModelUsageResponse, error)
	GetVendorUsage(context.Context, *GetVendorUsageRequest) (*GetVendorUsageResponse, error)
	GetTokenUsagePerApp(context.Context, *GetTokenUsagePerAppRequest) (*GetTokenUsagePerAppResponse, error)
	GetToolUsageStatistics(context.Context, *GetToolUsageStatisticsRequest) (*GetToolUsageStatisticsResponse, error)
	// App Management Operations
	ListApps(context.Context, *ListAppsRequest) (*ListAppsResponse, error)
	GetApp(context.Context, *GetAppRequest) (*GetAppResponse, error)
	CreateApp(context.Context, *CreateAppRequest) (*CreateAppResponse, error)
	UpdateApp(context.Context, *UpdateAppRequest) (*UpdateAppResponse, error)
	DeleteApp(context.Context, *DeleteAppRequest) (*DeleteAppResponse, error)
	// Tool Management Operations (High Priority)
	ListTools(context.Context, *ListToolsRequest) (*ListToolsResponse, error)
	GetTool(context.Context, *GetToolRequest) (*GetToolResponse, error)
	GetToolOperations(context.Context, *GetToolOperationsRequest) (*GetToolOperationsResponse, error)
	CallToolOperation(context.Context, *CallToolOperationRequest) (*CallToolOperationResponse, error)
	CreateTool(context.Context, *CreateToolRequest) (*CreateToolResponse, error)
	UpdateTool(context.Context, *UpdateToolRequest) (*UpdateToolResponse, error)
	DeleteTool(context.Context, *DeleteToolRequest) (*DeleteToolResponse, error)
	// Datasource Management Operations (Phase 1.1)
	ListDatasources(context.Context, *ListDatasourcesRequest) (*ListDatasourcesResponse, error)
	GetDatasource(context.Context, *GetDatasourceRequest) (*GetDatasourceResponse, error)
	CreateDatasource(context.Context, *CreateDatasourceRequest) (*CreateDatasourceResponse, error)
	UpdateDatasource(context.Context, *UpdateDatasourceRequest) (*UpdateDatasourceResponse, error)
	DeleteDatasource(context.Context, *DeleteDatasourceRequest) (*DeleteDatasourceResponse, error)
	SearchDatasources(context.Context, *SearchDatasourcesRequest) (*SearchDatasourcesResponse, error)
	ProcessDatasourceEmbeddings(context.Context, *ProcessEmbeddingsRequest) (*ProcessEmbeddingsResponse, error)
	// RAG/Embedding Operations for Plugins
	GenerateEmbedding(context.Context, *GenerateEmbeddingRequest) (*GenerateEmbeddingResponse, error)
	StoreDocuments(context.Context, *StoreDocumentsRequest) (*StoreDocumentsResponse, error)
	ProcessAndStoreDocuments(context.Context, *ProcessAndStoreRequest) (*ProcessAndStoreResponse, error)
	QueryDatasourceByVector(context.Context, *QueryByVectorRequest) (*QueryDatasourceResponse, error)
	// Advanced Datasource Operations - Metadata and Namespace Management
	DeleteDocumentsByMetadata(context.Context, *DeleteDocumentsByMetadataRequest) (*DeleteDocumentsByMetadataResponse, error)
	QueryByMetadataOnly(context.Context, *QueryByMetadataOnlyRequest) (*QueryByMetadataOnlyResponse, error)
	ListNamespaces(context.Context, *ListNamespacesRequest) (*ListNamespacesResponse, error)
	DeleteNamespace(context.Context, *DeleteNamespaceRequest) (*DeleteNamespaceResponse, error)
	// Data Catalogues Management Operations (Phase 1.2)
	ListDataCatalogues(context.Context, *ListDataCataloguesRequest) (*ListDataCataloguesResponse, error)
	GetDataCatalogue(context.Context, *GetDataCatalogueRequest) (*GetDataCatalogueResponse, error)
	CreateDataCatalogue(context.Context, *CreateDataCatalogueRequest) (*CreateDataCatalogueResponse, error)
	UpdateDataCatalogue(context.Context, *UpdateDataCatalogueRequest) (*UpdateDataCatalogueResponse, error)
	DeleteDataCatalogue(context.Context, *DeleteDataCatalogueRequest) (*DeleteDataCatalogueResponse, error)
	// Tags Management Operations (Phase 1.3)
	ListTags(context.Context, *ListTagsRequest) (*ListTagsResponse, error)
	GetTag(context.Context, *GetTagRequest) (*GetTagResponse, error)
	CreateTag(context.Context, *CreateTagRequest) (*CreateTagResponse, error)
	UpdateTag(context.Context, *UpdateTagRequest) (*UpdateTagResponse, error)
	DeleteTag(context.Context, *DeleteTagRequest) (*DeleteTagResponse, error)
	SearchTags(context.Context, *SearchTagsRequest) (*SearchTagsResponse, error)
	// Model Price Management Operations (Critical Priority)
	ListModelPrices(context.Context, *ListModelPricesRequest) (*ListModelPricesResponse, error)
	GetModelPrice(context.Context, *GetModelPriceRequest) (*GetModelPriceResponse, error)
	CreateModelPrice(context.Context, *CreateModelPriceRequest) (*CreateModelPriceResponse, error)
	UpdateModelPrice(context.Context, *UpdateModelPriceRequest) (*UpdateModelPriceResponse, error)
	DeleteModelPrice(context.Context, *DeleteModelPriceRequest) (*DeleteModelPriceResponse, error)
	GetModelPricesByVendor(context.Context, *GetModelPricesByVendorRequest) (*GetModelPricesByVendorResponse, error)
	// Filter Management Operations
	ListFilters(context.Context, *ListFiltersRequest) (*ListFiltersResponse, error)
	GetFilter(context.Context, *GetFilterRequest) (*GetFilterResponse, error)
	CreateFilter(context.Context, *CreateFilterRequest) (*CreateFilterResponse, error)
	UpdateFilter(context.Context, *UpdateFilterRequest) (*UpdateFilterResponse, error)
	DeleteFilter(context.Context, *DeleteFilterRequest) (*DeleteFilterResponse, error)
	// Vendor Information Operations
	GetAvailableLLMDrivers(context.Context, *GetAvailableLLMDriversRequest) (*GetAvailableLLMDriversResponse, error)
	GetAvailableEmbedders(context.Context, *GetAvailableEmbeddersRequest) (*GetAvailableEmbeddersResponse, error)
	GetAvailableVectorStores(context.Context, *GetAvailableVectorStoresRequest) (*GetAvailableVectorStoresResponse, error)
	// Plugin Key-Value Storage Operations
	WritePluginKV(context.Context, *WritePluginKVRequest) (*WritePluginKVResponse, error)
	ReadPluginKV(context.Context, *ReadPluginKVRequest) (*ReadPluginKVResponse, error)
	DeletePluginKV(context.Context, *DeletePluginKVRequest) (*DeletePluginKVResponse, error)
	// Agent Plugin Operations - Wrap REST APIs with credential injection
	ExecuteTool(context.Context, *ExecuteToolRequest) (*ExecuteToolResponse, error)
	QueryDatasource(context.Context, *QueryDatasourceRequest) (*QueryDatasourceResponse, error)
	CallLLM(*CallLLMRequest, grpc.ServerStreamingServer[CallLLMResponse]) error
	// Schedule Management Operations
	CreateSchedule(context.Context, *CreateScheduleRequest) (*CreateScheduleResponse, error)
	GetSchedule(context.Context, *GetScheduleRequest) (*GetScheduleResponse, error)
	ListSchedules(context.Context, *ListSchedulesRequest) (*ListSchedulesResponse, error)
	UpdateSchedule(context.Context, *UpdateScheduleRequest) (*UpdateScheduleResponse, error)
	DeleteSchedule(context.Context, *DeleteScheduleRequest) (*DeleteScheduleResponse, error)
	mustEmbedUnimplementedAIStudioManagementServiceServer()
}

